describe("Intl.supportedValuesOf",()=>{it("should return an array",()=>{let e=Intl.supportedValuesOf("timeZone");expect(Array.isArray(e)).toBe(!0)}),it("should contain common timezones",()=>{let e=Intl.supportedValuesOf("timeZone");expect(e).toContain("America/New_York"),expect(e).toContain("America/Los_Angeles"),expect(e).toContain("America/Denver"),expect(e).toContain("Europe/London"),expect(e).toContain("Europe/Paris"),expect(e).toContain("Asia/Tokyo"),expect(e).toContain("UTC")}),it("should return many timezones",()=>{let e=Intl.supportedValuesOf("timeZone");expect(e.length).toBeGreaterThan(400)})});describe("Intl.DateTimeFormat",()=>{describe("basic functionality",()=>{it("should be defined globally",()=>{expect(typeof Intl).toBe("object"),expect(typeof Intl.DateTimeFormat).toBe("function")}),it("should have correct Symbol.toStringTag",()=>{let e=new Intl.DateTimeFormat("en-US");expect(e[Symbol.toStringTag]).toBe("Intl.DateTimeFormat")})}),describe("formatToParts",()=>{it("should return an array of parts",()=>{let e=new Intl.DateTimeFormat("en-US",{timeZone:"UTC",year:"numeric",month:"2-digit",day:"2-digit"}),t=new Date("2022-03-02T15:45:34Z"),o=e.formatToParts(t);expect(Array.isArray(o)).toBe(!0),expect(o.length).toBeGreaterThan(0)}),it("should format date in specified timezone",()=>{let e=new Intl.DateTimeFormat("en-US",{timeZone:"America/Denver",hour12:!1,year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit",second:"2-digit"}),t=new Date("2022-03-02T15:45:34Z"),n=e.formatToParts(t).find(r=>r.type==="hour");expect(n?.value).toBe("08")}),it("should handle DST correctly",()=>{let e=new Intl.DateTimeFormat("en-US",{timeZone:"America/Denver",hour12:!1,hour:"2-digit"}),t=new Date("2024-06-15T18:00:00Z"),n=e.formatToParts(t).find(a=>a.type==="hour");expect(n?.value).toBe("12");let r=new Date("2024-01-15T18:00:00Z"),i=e.formatToParts(r).find(a=>a.type==="hour");expect(i?.value).toBe("11")})}),describe("format",()=>{it("should return a formatted string",()=>{let e=new Intl.DateTimeFormat("en-US",{timeZone:"UTC",year:"numeric",month:"2-digit",day:"2-digit"}),t=new Date("2022-03-02T15:45:34Z"),o=e.format(t);expect(typeof o).toBe("string"),expect(o).toContain("03"),expect(o).toContain("02"),expect(o).toContain("2022")})}),describe("resolvedOptions",()=>{it("should return resolved options",()=>{let t=new Intl.DateTimeFormat("en-US",{timeZone:"America/Denver",year:"numeric",month:"2-digit"}).resolvedOptions();expect(t.timeZone).toBe("America/Denver"),expect(t.locale).toBe("en-US"),expect(t.year).toBe("numeric"),expect(t.month).toBe("2-digit")}),it("should default to system timezone when not specified",()=>{let t=new Intl.DateTimeFormat("en-US").resolvedOptions();expect(typeof t.timeZone).toBe("string"),expect(t.timeZone.length).toBeGreaterThan(0)})})});
